package authorization

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/devportal/int/authorization"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type DevPortalAuthorizationProxy struct {
	authorization.UnimplementedDevPortalAuthorizationServer
	client authorization.DevPortalAuthorizationClient
}

func init() {
	proxyutil.Register(&authorization.DevPortalAuthorization_ServiceDesc, NewDevPortalAuthorizationProxy)
}
func NewDevPortalAuthorizationProxy(cc grpc.ClientConnInterface) authorization.DevPortalAuthorizationServer {
	return &DevPortalAuthorizationProxy{client: authorization.NewDevPortalAuthorizationClient(cc)}
}
func (p *DevPortalAuthorizationProxy) CanViewLogs(ctx context.Context, in *authorization.DevPortalAuthCanViewLogsRequest) (*authorization.DevPortalAuthorizationResponse, error) {
	return proxyutil.ProxyMethod[authorization.DevPortalAuthCanViewLogsRequest, authorization.DevPortalAuthorizationResponse](p.client.CanViewLogs)(ctx, in)
}
